import React, { useEffect } from 'react';

interface StyleGuideViewerProps {
  onClose: () => void;
  onStyleSelect: (styleValue: string) => void;
}

const STYLE_GUIDE_IMAGE_URL = 'https://i.ibb.co/cXcDzJjD/ai-style-new.png';

// Data for clickable hotspots on the style guide image.
// Based on the new image dimensions and layout
const IMAGE_WIDTH_PX = 1000; // Normalized for calculation
const IMAGE_HEIGHT_PX = 700; // Normalized for calculation

const HOTSPOT_WIDTH_PX = 90;
const HOTSPOT_HEIGHT_PX = 105;
const SPACING_X_PX = 8;
const SPACING_Y_PX = 10;

// Measured starting coordinates (top-left corner) for sections in the new image
const SECTION_1_START_X = 10;
const SECTION_1_START_Y = 50; // Illustration section start

const SECTION_2_START_X = 10;
const SECTION_2_START_Y = 460; // Vector/Other section start

const styleHotspots: { name: string; category: string; value: string; coords: { x: number; y: number; width: number; height: number; } }[] = [];

// Illustration styles (Top section)
const illustrationStyles = [
  'Hand-drawn', 'Grain', 'Bold Sketch', 'Pencil sketch', 'Retro Pop', 'Clay', 'Risograph', 'Color engraving', 'Pixel art', 'Engraving', 
  'Antiquarian', 'Bold fantasy', 'Child book', 'Hard Comics', 'Modern Folk', 'Multicolor', 'Neon Calm', 'Nostalgic pastel', 'Outline details', 'Tablet sketch', 
  'Young adult book', 'Seamless Digital', 'Plastic 3D', '3D render', 'Glow', 'Watercolor', 'Kawaii', 'Bright Scholar', '3D Soft Abstract', '3D Isometric Icon'
];

illustrationStyles.forEach((name, index) => {
    const row = Math.floor(index / 10);
    const col = index % 10;

    const x_px = SECTION_1_START_X + col * (HOTSPOT_WIDTH_PX + SPACING_X_PX);
    const y_px = SECTION_1_START_Y + row * (HOTSPOT_HEIGHT_PX + SPACING_Y_PX);

    styleHotspots.push({
        name,
        category: 'Illustration',
        value: `Illustration:${name}`,
        coords: {
            x: (x_px / IMAGE_WIDTH_PX) * 100,
            y: (y_px / IMAGE_HEIGHT_PX) * 100,
            width: (HOTSPOT_WIDTH_PX / IMAGE_WIDTH_PX) * 100,
            height: (HOTSPOT_HEIGHT_PX / IMAGE_HEIGHT_PX) * 100,
        }
    });
});

// Vector art styles (Bottom section)
const vectorStyles = [
  'Line art', 'Linocut', 'Color blobs', 'Bold stroke', 'Chemistry', 'Colored stencil', 'Cosmics', 'Marker outline', 'Mosaic', 'Naïvector', 
  'Roundish flat', 'Segmented Colors', 'Sharp contrast', 'Vector Photo', 'Vivid shapes', 'Seamless Vector', 'Cartoon', 'Vector Kawaii'
];

vectorStyles.forEach((name, index) => {
    const row = Math.floor(index / 10);
    const col = index % 10;

    const x_px = SECTION_2_START_X + col * (HOTSPOT_WIDTH_PX + SPACING_X_PX);
    const y_px = SECTION_2_START_Y + row * (HOTSPOT_HEIGHT_PX + SPACING_Y_PX);

    styleHotspots.push({
        name,
        category: 'Vector art',
        value: `Vector art:${name}`,
        coords: {
            x: (x_px / IMAGE_WIDTH_PX) * 100,
            y: (y_px / IMAGE_HEIGHT_PX) * 100,
            width: (HOTSPOT_WIDTH_PX / IMAGE_WIDTH_PX) * 100,
            height: (HOTSPOT_HEIGHT_PX / IMAGE_HEIGHT_PX) * 100,
        }
    });
});

export const StyleGuideViewer: React.FC<StyleGuideViewerProps> = ({ onClose, onStyleSelect }) => {
  useEffect(() => {
