        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex-shrink-0 p-4 border-b border-gray-700 flex items-center justify-between">
            <div>
                <h2 id="style-guide-title" className="text-xl font-bold text-cyan-300">
