            </div>
            <button
              onClick={onClose}
              className="p-2 bg-black/50 rounded-full text-gray-300 hover:text-white hover:bg-red-600 transition-colors"
              aria-label="Đóng"
            >
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24" strokeWidth={1.5} stroke="currentColor" className="w-6 h-6">
                    <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
