        {/* Image Content */}
        <div className="flex-1 overflow-auto p-4 bg-gray-950">
          <div className="relative inline-block min-w-full">
            <img
              src={STYLE_GUIDE_IMAGE_URL}
              alt="Style guide variations"
              className="block max-w-full h-auto mx-auto shadow-2xl"
            />
            {styleHotspots.map(hotspot => (
                <div
                    key={hotspot.value}
                    title={`${hotspot.category}: ${hotspot.name}`}
                    aria-label={`Chọn style: ${hotspot.name}`}
                    className="absolute group transition-all duration-200"
                    style={{
                        left: `${hotspot.coords.x}%`,
                        top: `${hotspot.coords.y}%`,
                        width: `${hotspot.coords.width}%`,
                        height: `${hotspot.coords.height}%`,
                        cursor: 'pointer'
                    }}
                    onClick={() => onStyleSelect(hotspot.value)}
                >
                    <div className="w-full h-full bg-cyan-400/10 border-2 border-transparent group-hover:border-cyan-400 group-hover:bg-cyan-400/20 rounded-lg transition-all"></div>
                </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

