import { GoogleGenAI, Modality } from "@google/genai";
import type { GeneratedImage } from '../types';

const fileToBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve((reader.result as string).split(',')[1]);
    reader.onerror = (error) => reject(error);
  });
};

/**
 * Xóa metadata bằng cách vẽ lại ảnh lên Canvas.
 * Canvas chỉ lưu trữ dữ liệu pixel, bỏ qua mọi thông tin EXIF/Metadata đính kèm.
 */
const stripMetadata = async (base64Data: string, mimeType: string): Promise<string> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d');
      if (!ctx) {
        resolve(base64Data); // Fallback nếu không tạo được context
        return;
      }
      ctx.drawImage(img, 0, 0);
      // Trích xuất lại ảnh, lúc này metadata đã bị loại bỏ
      const strippedDataUrl = canvas.toDataURL(mimeType);
      resolve(strippedDataUrl.split(',')[1]);
    };
    img.onerror = reject;
    img.src = `data:${mimeType};base64,${base64Data}`;
  });
};

export const generateImageVariations = async (
  imageFile: File | null,
  prompts: string[],
  referenceImageFiles: File[],
  maskFile: File | null,
  aspectRatio: string
): Promise<GeneratedImage[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const generateSingleImage = async (prompt: string, parts: any[]): Promise<GeneratedImage> => {
    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: { parts: parts },
        config: {
          responseModalities: [Modality.IMAGE],
          imageConfig: {
            aspectRatio: aspectRatio as any,
            imageSize: '2K',
          }
        },
      });

      let imageUrl = '';
      let text: string | null = null;

      if (response.candidates && response.candidates[0].content.parts) {
          for (const part of response.candidates[0].content.parts) {
            if (part.inlineData) {
              const mimeType = part.inlineData.mimeType;
              const rawBase64 = part.inlineData.data;

              // Xóa metadata trước khi hiển thị/trả về
              try {
                const cleanBase64 = await stripMetadata(rawBase64, mimeType);
                imageUrl = `data:${mimeType};base64,${cleanBase64}`;
              } catch (e) {
                console.error("Metadata stripping failed, using raw image", e);
                imageUrl = `data:${mimeType};base64,${rawBase64}`;
              }
            } else if (part.text) {
              text = part.text;
            }
          }
      }

      if (!imageUrl) {
          throw new Error('No image was generated for the prompt.');
      }

      return { prompt, imageUrl, text };

    } catch (error) {
      console.error(`Error generating image for prompt "${prompt}":`, error);
      return {
        prompt,
        imageUrl: 'error',
        text: error instanceof Error ? error.message : 'An unknown error occurred.',
      };
    }
  };

  if (!imageFile) {
    const generationPromises = prompts.map(async (prompt) => {
        const parts = [{ text: prompt }];
        return generateSingleImage(prompt, parts);
    });
    return Promise.all(generationPromises);
  }

  const base64ImageData = await fileToBase64(imageFile);
  const mimeType = imageFile.type;

  const generationPromises = prompts.map(async (prompt) => {
      const imageParts: { inlineData: { data: string; mimeType: string; }; }[] = [
        {
          inlineData: {
            data: base64ImageData,
            mimeType: mimeType,
          },
        },
      ];

      if (maskFile) {
        const base64MaskData = await fileToBase64(maskFile);
        imageParts.push({
          inlineData: {
            data: base64MaskData,
            mimeType: maskFile.type,
          },
        });
      }

      if (referenceImageFiles && referenceImageFiles.length > 0) {
        const referenceImagePromises = referenceImageFiles.map(async (file) => {
          const base64Data = await fileToBase64(file);
          return {
            inlineData: {
              data: base64Data,
              mimeType: file.type,
            },
          };
        });
        const referenceImageParts = await Promise.all(referenceImagePromises);
        imageParts.push(...referenceImageParts);
      }

      const parts = [...imageParts, { text: prompt }];
      return generateSingleImage(prompt, parts);
  });

  return Promise.all(generationPromises);
};

