                title="Select a visual style"
            >
                <span className={`truncate ${selectedStyle ? 'text-cyan-300' : 'text-gray-400'}`}>
                    {selectedStyle ? selectedStyle.split(':')[1] : 'Select Style'}
                </span>
                    {selectedStyle ? (
                    <span 
                        role="button"
                        onClick={(e) => {e.stopPropagation(); onStyleChange('');}}
