                ) : <PaletteIcon className="w-5 h-5 ml-1 flex-shrink-0" />}
            </button>

            <div className="relative w-full">
                <select
                id="backgroundStyle"
                value={backgroundStyle}
                onChange={(e) => onBackgroundChange(e.target.value)}
                className="w-full bg-gray-700 border border-gray-600 rounded-md px-3 py-2.5 text-base text-gray-300 focus:border-cyan-500 outline-none appearance-none truncate"
                >
                <option value="none">Default BG</option>
                <option value="black">Black BG</option>
                <option value="white">White BG</option>
                <option value="transparent">Transparent</option>
                </select>
            </div>
        </div>

        {/* Outline Section */}
        <div className="space-y-2">
            <label className="text-base font-bold text-gray-400 uppercase tracking-wider">Viền Chủ Thể (Outline)</label>
            <div className="grid grid-cols-2 gap-3">
                <div className="relative w-full">
