  const [historyImages, setHistoryImages] = useState<GeneratedImage[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [fullscreenImage, setFullscreenImage] = useState<GeneratedImage | null>(null);
  const [isStyleGuideVisible, setIsStyleGuideVisible] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<string>('1:1');
  const [selectedStyle, setSelectedStyle] = useState<string>('');

  const [outlineType, setOutlineType] = useState<'none' | 'white' | 'black'>('none');
  const [outlineThickness, setOutlineThickness] = useState<'thin' | 'normal' | 'thick'>('normal');

  const [promptOptions, setPromptOptions] = useState({
    cuteStyle: false,
    styleCuteSimplifiedCartoon: false,
    styleSimplified: false,
    keepStyle: false,
    keepStartImageStyle: false,
    keepReferenceRatio: false,
  });
  const [backgroundStyle, setBackgroundStyle] = useState('none'); 
  const [isApiKeyValid, setIsApiKeyValid] = useState<boolean>(false);

  useEffect(() => {
    const verifyApiKey = async () => {
      if (typeof window !== 'undefined' && (window as any).aistudio) {
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setIsApiKeyValid(hasKey);
      } else {
        setIsApiKeyValid(true); 
      }
    };
    verifyApiKey();
  }, []);

  const handleApiKeySelection = async () => {
    if (typeof window !== 'undefined' && (window as any).aistudio) {
      try {
        await (window as any).aistudio.openSelectKey();
        const hasKey = await (window as any).aistudio.hasSelectedApiKey();
        setIsApiKeyValid(hasKey);
      } catch (e) {
        console.error("API Key selection failed", e);
      }
    }
  };

  const BACKGROUND_PROMPT_MAP = {
    black: ', isolated on black background',
    white: ', isolated on white background',
    transparent: ', transparent background',
  };

  const PROMPT_OPTIONS_MAP = {
    cuteStyle: ', cute simple Flat 2D style',
    styleCuteSimplifiedCartoon: ', cute simplified cartoon style',
    styleSimplified: ', make it very simplified',
    keepStyle: ', Adjust uploaded image to graphic style like as Reference Image',
    keepStartImageStyle: ', keep graphic style like as Upload Image',
    keepReferenceRatio: ', keep aspect ratio of reference image',
  };

  const handleOptionChange = (option: keyof typeof promptOptions) => {
    setPromptOptions(prevOptions => ({
      ...prevOptions,
      [option]: !prevOptions[option],
    }));
  };

  const handleImageSelect = useCallback((file: File) => {
    const previewUrl = URL.createObjectURL(file);
    setImage({ file, previewUrl });

    const img = new Image();
    img.onload = () => {
      const closest = getClosestAspectRatio(img.naturalWidth, img.naturalHeight);
      setAspectRatio(closest);
    };
    img.src = previewUrl;

    setGeneratedImages([]);
    setError(null);
  }, []);

  const handleImageRemove = useCallback(() => {
    if (image) {
      URL.revokeObjectURL(image.previewUrl);
      setImage(null);
    }
    if (maskImage) {
        URL.revokeObjectURL(maskImage.previewUrl);
        setMaskImage(null);
    }
    referenceImages.forEach(refImg => URL.revokeObjectURL(refImg.previewUrl));
    setReferenceImages([]);
    setGeneratedImages([]);
    setError(null);
  }, [image, referenceImages, maskImage]);

  const handleMaskSelect = useCallback((file: File) => {
    if (maskImage) {
        URL.revokeObjectURL(maskImage.previewUrl);
    }
    setMaskImage({
      file,
      previewUrl: URL.createObjectURL(file),
    });
  }, [maskImage]);

  const handleMaskRemove = useCallback(() => {
    if (maskImage) {
      URL.revokeObjectURL(maskImage.previewUrl);
      setMaskImage(null);
    }
  }, [maskImage]);


  const handleAddReferenceImage = useCallback((file: File) => {
    setReferenceImages(prev => [...prev, {
      file,
      previewUrl: URL.createObjectURL(file),
    }]);
  }, []);

  const handleRemoveReferenceImage = useCallback((indexToRemove: number) => {
    setReferenceImages(prev => {
        const imageToRemove = prev[indexToRemove];
        if (imageToRemove) {
            URL.revokeObjectURL(imageToRemove.previewUrl);
        }
        return prev.filter((_, index) => index !== indexToRemove);
    });
  }, []);


  const handleGenerateClick = async () => {
    const activePrompts = prompts.filter(p => p.trim() !== '');
    if (activePrompts.length === 0) {
      setError('Vui lòng cung cấp ít nhất một mô tả.');
      return;
    }

    setIsLoading(true);
    setError(null);
    setGeneratedImages([]);

    const finalPrompts = activePrompts.map(prompt => {
      let finalPrompt = prompt.trim();

      if (selectedStyle) {
        const parts = selectedStyle.split(':');
        const styleName = parts.length > 1 ? parts[1] : parts[0];
        if (styleName) {
            finalPrompt += ` style ${styleName}`;
        }
      }

      if (backgroundStyle !== 'none' && BACKGROUND_PROMPT_MAP[backgroundStyle as keyof typeof BACKGROUND_PROMPT_MAP]) {
        finalPrompt += BACKGROUND_PROMPT_MAP[backgroundStyle as keyof typeof BACKGROUND_PROMPT_MAP];
      }

      if (outlineType !== 'none') {
        const thicknessStr = outlineThickness === 'thin' ? 'a fine' : outlineThickness === 'thick' ? 'a bold thick' : 'a solid';
        finalPrompt += `, add ${thicknessStr} ${outlineType} outline around the subject`;
      }

      if (promptOptions.cuteStyle) {
          finalPrompt += PROMPT_OPTIONS_MAP.cuteStyle;
      }
      if (promptOptions.styleCuteSimplifiedCartoon) {
        finalPrompt += PROMPT_OPTIONS_MAP.styleCuteSimplifiedCartoon;
      }
      if (promptOptions.styleSimplified) {
        finalPrompt += PROMPT_OPTIONS_MAP.styleSimplified;
      }
      if (promptOptions.keepStyle && referenceImages.length > 0) {
        finalPrompt += PROMPT_OPTIONS_MAP.keepStyle;
      }
      if (promptOptions.keepReferenceRatio && referenceImages.length > 0) {
        finalPrompt += PROMPT_OPTIONS_MAP.keepReferenceRatio;
      }
      if (promptOptions.keepStartImageStyle && image) {
        finalPrompt += PROMPT_OPTIONS_MAP.keepStartImageStyle;
      }
      return finalPrompt;
    });

    try {
      const results = await generateImageVariations(
        image?.file ?? null,
        finalPrompts,
        referenceImages.map(img => img.file),
        maskImage?.file ?? null,
        aspectRatio
      );
      setGeneratedImages(results);

      // Cập nhật lịch sử (lưu 10 hình mới nhất)
      const validResults = results.filter(img => img.imageUrl !== 'error');
      if (validResults.length > 0) {
        setHistoryImages(prev => {
            const combined = [...validResults, ...prev];
            return combined.slice(0, 10);
        });
      }

    } catch (err) {
      console.error(err);
      setError(err instanceof Error ? err.message : 'An unexpected error occurred during generation.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleStyleSelectFromGuide = useCallback((styleValue: string) => {
    setSelectedStyle(styleValue);
    setIsStyleGuideVisible(false);
  }, []);

  const handleUseImageAsInput = useCallback(async (generatedImage: GeneratedImage) => {
    const newFileName = `generated_${generatedImage.prompt.replace(/[^a-z0-9]/gi, '_').toLowerCase().slice(0, 20)}.png`;
    const file = dataURLtoFile(generatedImage.imageUrl, newFileName);

    if (!file) {
      setError("Could not use this image as input.");
      return;
    }

    if (image) {
      URL.revokeObjectURL(image.previewUrl);
    }
    if (maskImage) {
        URL.revokeObjectURL(maskImage.previewUrl);
    }
    referenceImages.forEach(refImg => URL.revokeObjectURL(refImg.previewUrl));

    setImage({
      file,
      previewUrl: URL.createObjectURL(file),
    });

    setGeneratedImages([]);
    setMaskImage(null);
    setReferenceImages([]);
    setError(null);
  }, [image, referenceImages, maskImage]);

  const handleDownloadImage = useCallback((imageToDownload: GeneratedImage) => {
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      canvas.width = img.naturalWidth;
      canvas.height = img.naturalHeight;
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      ctx.fillStyle = "#FFFFFF";
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.drawImage(img, 0, 0);

      const jpgUrl = canvas.toDataURL('image/jpeg', 0.92);
      const link = document.createElement('a');
      link.href = jpgUrl;
      const sanitizedPrompt = imageToDownload.prompt.replace(/[^a-z0-9]/gi, '_').toLowerCase();
      link.download = `variation_${sanitizedPrompt.slice(0, 50)}.jpg`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    };
    img.src = imageToDownload.imageUrl;
  }, []);

  const handleUseImageFromViewer = useCallback(async (generatedImage: GeneratedImage) => {
    await handleUseImageAsInput(generatedImage);
    setFullscreenImage(null);
  }, [handleUseImageAsInput]);

  const canGenerate = prompts.some(p => p.trim() !== '') && !isLoading;

  if (!isApiKeyValid) {
    return (
      <div className="flex flex-col items-center justify-center h-screen bg-gray-900 text-gray-200">
        <h1 className="text-3xl font-bold mb-4 text-cyan-400">API Key Selection Required</h1>
        <p className="mb-6 text-lg text-gray-400">
          To use the Nano Banana Pro model, you must select a valid API key.
        </p>
        <button
          onClick={handleApiKeySelection}
          className="px-6 py-3 bg-cyan-600 hover:bg-cyan-500 rounded-lg text-white font-semibold transition-colors"
        >
          Select API Key
        </button>
        <a 
          href="https://ai.google.dev/gemini-api/docs/billing" 
          target="_blank" 
          rel="noopener noreferrer"
          className="mt-4 text-sm text-gray-500 hover:text-cyan-400 underline"
        >
          Billing Documentation
        </a>
      </div>
    );
  }

  return (
    <>
      <div className="flex flex-col lg:flex-row lg:h-screen bg-gray-900 text-gray-200 font-sans lg:overflow-hidden">
          <aside className="w-full lg:w-[480px] flex-shrink-0 flex flex-col border-b lg:border-b-0 lg:border-r border-gray-700 bg-gray-800/50 lg:h-full">
            <div className="lg:flex-1 lg:overflow-y-auto p-6 space-y-6 custom-scrollbar">
                <header>
                  <h1 className="text-3xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-cyan-300 to-blue-500">
                    AI Image Variator
                  </h1>
                </header>

                <PromptManager prompts={prompts} setPrompts={setPrompts} hasImage={!!image} />

                <PromptOptions
                    options={promptOptions}
                    onOptionChange={handleOptionChange}
                    backgroundStyle={backgroundStyle}
                    onBackgroundChange={setBackgroundStyle}
                    selectedStyle={selectedStyle}
                    onStyleChange={setSelectedStyle}
                    outlineType={outlineType}
                    onOutlineTypeChange={setOutlineType}
                    outlineThickness={outlineThickness}
                    onOutlineThicknessChange={setOutlineThickness}
                    hasReferenceImages={referenceImages.length > 0}
                    hasStartImage={!!image}
                    onShowStyleGuide={() => setIsStyleGuideVisible(true)}
                />

                <ImageUploader onImageSelect={handleImageSelect} image={image} onImageRemove={handleImageRemove} />

                <div className="grid grid-cols-2 gap-3">
                    <MaskUploader
                        onMaskSelect={handleMaskSelect}
                        mask={maskImage}
                        onMaskRemove={handleMaskRemove}
                        isDisabled={!image}
                    />
                     <ReferenceImageUploader 
                        onImageAdd={handleAddReferenceImage}
                        onImageRemove={handleRemoveReferenceImage}
                        images={referenceImages}
                        isDisabled={!image}
                    />
                </div>

                <AspectRatioSelector
                    aspectRatio={aspectRatio}
                    setAspectRatio={setAspectRatio}
                />
            </div>

            <div className="p-6 border-t border-gray-700 bg-gray-900/50 backdrop-blur-md z-10 sticky bottom-0 lg:static">
                  <button
                      onClick={handleGenerateClick}
                      disabled={!canGenerate}
                      className={`w-full text-lg font-semibold py-3 px-4 rounded-lg transition-all duration-300 flex items-center justify-center ${
                          canGenerate
                          ? 'bg-gradient-to-r from-cyan-600 to-blue-700 hover:from-cyan-500 hover:to-blue-600 text-white shadow-lg transform hover:scale-[1.02]'
                          : 'bg-gray-700 cursor-not-allowed text-gray-500'
                      }`}
                  >
                      {isLoading ? (
                          <>
                              <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                              </svg>
                              Đang tạo...
                          </>
                      ) : 'Generate Images'}
                  </button>
                  {error && <p className="text-red-400 text-base text-center mt-2">{error}</p>}
            </div>
          </aside>

          <main className="flex-1 bg-gray-900 p-2 flex flex-col lg:overflow-hidden min-h-[500px] lg:min-h-0">
             <div className="flex items-center justify-between mb-2 px-1 flex-shrink-0">
                <h2 className="text-base font-bold text-cyan-300 uppercase tracking-wider">Kết quả</h2>
                {historyImages.length > 0 && (
                    <button 
                        onClick={() => setHistoryImages([])}
                        className="text-[10px] text-gray-500 hover:text-red-400 uppercase font-bold tracking-tighter transition-colors"
                    >
                        Xóa lịch sử
                    </button>
                )}
             </div>
              <div className="flex-1 lg:overflow-y-auto rounded-lg border border-gray-800 bg-gray-800/20 mb-2">
                <ResultsDisplay 
                    originalImage={image} 
                    generatedImages={generatedImages}
                    isLoading={isLoading}
                    onImageSelect={setFullscreenImage}
                    onUseAsInput={handleUseImageAsInput}
                />
              </div>

              {/* History Section */}
              <div className="h-32 flex-shrink-0 border-t border-gray-800 pt-2">
                 <HistoryDisplay 
                    images={historyImages} 
                    onImageSelect={setFullscreenImage}
                    onUseAsInput={handleUseImageAsInput}
                    onDownload={handleDownloadImage}
                 />
              </div>
          </main>
      </div>

      {isStyleGuideVisible && (
        <StyleGuideViewer
          onClose={() => setIsStyleGuideVisible(false)}
          onStyleSelect={handleStyleSelectFromGuide}
        />
      )}
      {fullscreenImage && (
        <FullscreenViewer 
            image={fullscreenImage} 
            onClose={() => setFullscreenImage(null)}
            onDownload={() => handleDownloadImage(fullscreenImage)}
            onUseAsInput={() => handleUseImageFromViewer(fullscreenImage)}
        />
      )}
    </>
  );
};

